-- ============================================================================
-- Fleet CTA — 10-Vehicle Fully-Populated Demo Seed
-- ============================================================================
-- Idempotent: DELETE all dev tenant data, then INSERT fresh.
-- Run:  psql -d fleet_db -f api/src/db/seeds/seed-demo-10.sql
-- Then: redis-cli FLUSHDB && cd api && npm run dev
-- ============================================================================

BEGIN;

SET app.current_tenant_id = '12345678-1234-1234-1234-123456789012';

-- ============================================================================
-- 0. CLEANUP — disable FK checks, delete all dev tenant data, re-enable
-- ============================================================================
-- Temporarily bypass FK constraints during cleanup (PostgreSQL session-level)
SET session_replication_role = 'replica';

ALTER TABLE documents DISABLE TRIGGER ALL;

-- Delete from ALL seeded tables (order doesn't matter with FKs disabled)
DELETE FROM notifications          WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM budgets                WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM reservations           WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
