DELETE FROM driver_hos_logs        WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM driver_scores_history  WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM driver_scorecards      WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM announcements          WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM policy_acknowledgments WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM policy_violations      WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
