DELETE FROM training_courses       WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM certifications         WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM compliance_records     WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM compliance_requirements WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM documents              WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM purchase_orders        WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM parts_inventory        WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM vendors                WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM charging_sessions      WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM charging_stations      WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM inspections            WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM tasks                  WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM incidents              WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM maintenance_schedules  WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM fuel_transactions      WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM work_orders            WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM dispatch_channels      WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM dispatch_channels      WHERE tenant_id IS NULL;
DELETE FROM policy_templates      WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM policy_templates      WHERE tenant_id IS NULL;
DELETE FROM dispatches             WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM routes                 WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM geofences              WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM vehicle_assignments    WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM vehicles               WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM drivers                WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM facilities             WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM users                  WHERE tenant_id = '12345678-1234-1234-1234-123456789012';
DELETE FROM tenants                WHERE id = '12345678-1234-1234-1234-123456789012';

-- Re-enable FK constraint checking
SET session_replication_role = 'origin';

