('97000000-0000-0000-0000-000000000003', '12345678-1234-1234-1234-123456789012', 'CMP-DAP-001', 'Drug and Alcohol Policy',         'Compliance',  'Maintain a drug and alcohol-free workplace compliant with DOT/FMCSA regulations', 'All safety-sensitive employees including drivers, mechanics, and dispatchers',  'CTA Fleet maintains a zero-tolerance drug and alcohol policy...', '3.0', '2025-01-01', 'Active', true),
('97000000-0000-0000-0000-000000000004', '12345678-1234-1234-1234-123456789012', 'CMP-HOS-001', 'Hours of Service Compliance',     'Compliance',  'Ensure ELD usage and HOS compliance for commercial motor vehicle operators',      'All drivers operating commercial motor vehicles (CMVs)',                       'All drivers operating commercial motor vehicles must comply with FMCSA HOS regulations...', '2.0', '2025-01-01', 'Active', true),
('97000000-0000-0000-0000-000000000005', '12345678-1234-1234-1234-123456789012', 'SAF-PPE-001', 'Personal Protective Equipment',   'Safety',      'Protect employees from workplace hazards through proper PPE use',                 'All employees exposed to workplace hazards in maintenance and field operations','All maintenance personnel must wear appropriate PPE including safety glasses, steel-toe boots...', '1.2', '2025-06-01', 'Active', true),
('97000000-0000-0000-0000-000000000006', '12345678-1234-1234-1234-123456789012', 'OPS-FUL-001', 'Fuel Card Usage Policy',          'Operations',  'Ensure proper use and reconciliation of fleet fuel cards',                         'All drivers and fleet managers with assigned fuel cards',                      'Fleet fuel cards are to be used only for authorized fuel purchases for assigned vehicles...', '1.0', '2025-01-01', 'Active', true),
('97000000-0000-0000-0000-000000000007', '12345678-1234-1234-1234-123456789012', 'OPS-EVC-001', 'EV Charging Protocol',            'Operations',  'Establish procedures for safe and efficient charging of electric fleet vehicles',  'All employees assigned to or operating electric fleet vehicles',               'Electric vehicles must be charged at CTA-approved charging stations...', '1.0', '2025-03-01', 'Active', true),
